import{_ as l,o as i,c as e,a2 as n}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"CPO 光通訊六巨頭深度報告","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/光通訊研究/CPO六巨頭深度報告_2026-05-04.md","filePath":"Deep32Q知識庫/產業洞察/光通訊研究/CPO六巨頭深度報告_2026-05-04.md"}'),r={name:"Deep32Q知識庫/產業洞察/光通訊研究/CPO六巨頭深度報告_2026-05-04.md"};function a(s,t,o,g,d,p){return i(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="cpo-光通訊六巨頭深度報告" tabindex="-1">CPO 光通訊六巨頭深度報告 <a class="header-anchor" href="#cpo-光通訊六巨頭深度報告" aria-label="Permalink to &quot;CPO 光通訊六巨頭深度報告&quot;">​</a></h1><p><strong>日期：</strong> 2026-05-04 <strong>研究範圍：</strong> 全新光電 (2455)、IET-KY 新思 (6530)、上詮 (3362)、眾達-KY (4977)、光聖 (6442)、波若威 (3163)</p><hr><h2 id="一、產業背景-cpo-技術轉折點" tabindex="-1">一、產業背景：CPO 技術轉折點 <a class="header-anchor" href="#一、產業背景-cpo-技術轉折點" aria-label="Permalink to &quot;一、產業背景：CPO 技術轉折點&quot;">​</a></h2><p>2026 年被業界定調為「矽光子技術商轉元年」。輝達（NVIDIA）Rubin Ultra 世代登場，高速互連架構呈現「銅退光進」的關鍵轉折點。台積電 COUPE 矽光子平台預計 2026 年進入量產，實現電子與光子積體電路的異質整合。</p><p><strong>核心趨勢：</strong></p><ul><li>800G → 1.6T → 3.2T 規格快速升級</li><li>AI 資料中心內建光模組成為標準配置</li><li>大型叢集部署數萬個光模組，InP 需求結構性放大</li></ul><hr><h2 id="二、六家公司深度分析" tabindex="-1">二、六家公司深度分析 <a class="header-anchor" href="#二、六家公司深度分析" aria-label="Permalink to &quot;二、六家公司深度分析&quot;">​</a></h2><h3 id="_1-全新光電-2455-—-inp-磊晶龍頭" tabindex="-1">1. 全新光電 (2455) — InP 磊晶龍頭 <a class="header-anchor" href="#_1-全新光電-2455-—-inp-磊晶龍頭" aria-label="Permalink to &quot;1. 全新光電 (2455) — InP 磊晶龍頭&quot;">​</a></h3><p><strong>核心產品：</strong> GaAs 與 InP 磊晶片（手機 PA、WiFi、高速光通訊）</p><p><strong>關鍵數據：</strong></p><ul><li>2026 年 1 月營收 3.4 億元，月增 6.6%、年增 30.25%，創歷年同期新高</li><li>2025 全年營收 33.8 億元，年增 4.29%；淨利年減 18.35%，EPS 2.97 元</li><li>光電子營收占比近三成（Q4 約 2.8 億元，占 29.3%）創歷史新高</li></ul><p><strong>技術進度：</strong></p><ul><li>800G 接收端產品：2025 年出貨三位數成長</li><li>1.6T PD 產品：已完成驗證，3–4 月開始出貨</li><li>CW Laser 發射端：較去年三位數成長，Q3–Q4 進入量產</li><li>200G PD：客戶要求下 Q2 提前量產</li></ul><p><strong>擴產計畫：</strong></p><ul><li>新購 5 台 MOCVD（GaN 1 台、InP 4 台），Q3 到廠，總數從 62 增至 67 台</li><li>積極尋找平鎮工業區及大桃園工業區土地廠房</li></ul><p><strong>市場預期：</strong></p><ul><li>2026 全年營收年增約 19%–25.7%</li><li>光收發器相關磊晶產品較 2025 年翻倍成長</li></ul><p><strong>風險因素：</strong></p><ul><li>中國對 InP 基板出口管制，供應鏈需導入德、日第二/三供應來源</li><li>毛利率由過往約 42% 滑落至 2025 年約 36%，短期結構牽制</li><li>GaAs 微電子端基板成本不易轉嫁，手機市場成長有限</li></ul><p><strong>資料來源：</strong></p><ol><li>鉅亨網優分析 (2026-03-02)：全新光電 1 月營收創高分析</li><li>TechNews (2026-03-23)：光電子業務營收占比近三成</li><li>TechNews (2026-04-28)：VCSEL 與 QD 雷射技術趨勢</li></ol><hr><h3 id="_2-iet-ky-新思-6530-—-vcsel-qd-雷射雙軌" tabindex="-1">2. IET-KY 新思 (6530) — VCSEL + QD 雷射雙軌 <a class="header-anchor" href="#_2-iet-ky-新思-6530-—-vcsel-qd-雷射雙軌" aria-label="Permalink to &quot;2. IET-KY 新思 (6530) — VCSEL + QD 雷射雙軌&quot;">​</a></h3><p><strong>核心產品：</strong> VCSEL（垂直腔面發射雷射）、量子點雷射（QD Laser）</p><p><strong>關鍵進展：</strong></p><ul><li>200G VCSEL：預期 2026 年量產</li><li>200G PD：小量產中，待基板到位即大量生產</li><li>QD 雷射機台：Q4 提前就位，低軌衛星有望成為 AI 之外第二成長引擎</li></ul><p><strong>產能擴張：</strong></p><ul><li>未來幾年整體產能規模預計提升超過 50%</li><li>獨特的 MBE 技術（相對於 MOCVD，在精準度與自組裝控制上更適合 QD 雷射）</li></ul><p><strong>結盟動態：</strong></p><ul><li>與光聖透過換股結盟，有利卡位 CPO 領域</li></ul><p><strong>市場預期：</strong></p><ul><li>2026 年營收年增 29.84%</li></ul><p><strong>技術優勢：</strong></p><ul><li>VCSEL：製造成本低（低於邊緣發射雷射器）、功耗效率高、適用多模光纖傳輸</li><li>QD 雷射：對晶格缺陷具高度容忍性，易與矽基板整合；高溫穩定輸出；多波長梳狀光源支援 WDM</li></ul><p><strong>資料來源：</strong></p><ol><li>TechNews (2026-04-28)：VCSEL 與 QD 雷射可望成 AI 光通訊新解方</li></ol><hr><h3 id="_3-上詮-3362-—-fau-光纖陣列龍頭" tabindex="-1">3. 上詮 (3362) — FAU 光纖陣列龍頭 <a class="header-anchor" href="#_3-上詮-3362-—-fau-光纖陣列龍頭" aria-label="Permalink to &quot;3. 上詮 (3362) — FAU 光纖陣列龍頭&quot;">​</a></h3><p><strong>核心產品：</strong> FAU（Fiber Array Unit，光纖陣列單元）</p><p><strong>關鍵數據與進度：</strong></p><ul><li>與台積電在 FAU 產品研發已有至少三年合作</li><li>FAU 規格已開發至 1.6T 及 3.2T</li><li>最快 2026 年交付 1.6T 產品，2027 大量交付 3.2T</li><li>6.4T 產品有望明年（2027）開始量產出貨</li></ul><p><strong>台積電 COUPE 整合：</strong></p><ul><li>台積電 COUPE 矽光子平台 2026 年進入量產</li><li>上詮為台積電 CPO 生態系統重要合作夥伴</li><li>生產節奏與輝達 Rubin 架構發展路徑幾乎同步</li></ul><p><strong>技術優勢：</strong></p><ul><li>專利平台 ReLFACon™ 解決矽光子高溫封裝中 FAU 損耗難題</li><li>2026 年資本支出超過新台幣 10 億元用於 CPO FAU 自動化生產和測試設備</li></ul><p><strong>市場預期：</strong></p><ul><li>摩根士丹利大幅上調目標價</li><li>輝達相關 CPO 訂單營收占比到 2028 年可能提升至 80%</li><li>2026 下半年至 2027 年將是 Vera Rubin 和 Rubin Ultra 平台 CPO 產品關鍵放量期</li></ul><p><strong>資料來源：</strong></p><ol><li>TrendForce (2026-04-01)：台積電 COUPE 矽光子平台 2026 年量產</li><li>Cnyes (2026-01-28)：矽光子族群漲停分析</li></ol><hr><h3 id="_4-眾達-ky-4977-—-cpo-雷射光學模組" tabindex="-1">4. 眾達-KY (4977) — CPO 雷射光學模組 <a class="header-anchor" href="#_4-眾達-ky-4977-—-cpo-雷射光學模組" aria-label="Permalink to &quot;4. 眾達-KY (4977) — CPO 雷射光學模組&quot;">​</a></h3><p><strong>核心產品：</strong> 光收發模組、CPO 雷射光學封裝、外置雷射封裝（ELSFP）</p><p><strong>關鍵進展：</strong></p><ul><li>與博通（Broadcom）長期密切合作，獨家供應其 51.2T CPO 方案</li><li>CPO 產品預計 2026 年進入快速量產階段並開始放量出貨</li><li>目前約六成營收來自 400G 和 800G 產品</li><li>開發中：128G 光纖通道產品</li></ul><p><strong>雙工廠策略：</strong></p><ul><li>中國蘇州 + 馬來西亞檳城生產基地，分散風險</li></ul><p><strong>市場預期：</strong></p><ul><li>2026 年 CPO 營收佔比持續提升</li><li>2026 年 EPS 年增率可望達到近 10%</li></ul><p><strong>風險因素：</strong></p><ul><li>CPO 放量時程取決於博通客戶認證與 CSP 建置節奏</li></ul><p><strong>資料來源：</strong></p><ol><li>TaiwanHot (2026-03)：眾達-KY 3 月營收達 0.85 億元以上</li><li>Cnyes (2026-01-28)：眾達-KY 連袂亮燈漲停分析</li></ol><hr><h3 id="_5-光聖-6442-—-inp-矽光子龍頭" tabindex="-1">5. 光聖 (6442) — InP 矽光子龍頭 <a class="header-anchor" href="#_5-光聖-6442-—-inp-矽光子龍頭" aria-label="Permalink to &quot;5. 光聖 (6442) — InP 矽光子龍頭&quot;">​</a></h3><p><strong>核心產品：</strong> InP 雷射晶片、800G/1.6T 光模組</p><p><strong>關鍵數據：</strong></p><ul><li>2025 年第四季營收創高，受惠 AI 伺服器需求強勁</li><li>市場預期 2026 年 EPS 有望突破 40 元</li><li>外資調升目標價至 3,000 元</li></ul><p><strong>技術進度：</strong></p><ul><li>800G 升級需求推升光纖模組訂單</li><li>美系客戶大廠支持建置 AI 伺服器需求強勁</li></ul><p><strong>風險因素：</strong></p><ul><li>股價已創新高（跳空衝上 1,570 元），短期漲幅大</li><li>高度集中於單一客戶群</li></ul><p><strong>資料來源：</strong></p><ol><li>Cnyes (2026-01-28)：矽光子再發光！光聖、波若威、眾達-KY 連袂亮燈</li></ol><hr><h3 id="_6-波若威-3163-—-光通訊模組" tabindex="-1">6. 波若威 (3163) — 光通訊模組 <a class="header-anchor" href="#_6-波若威-3163-—-光通訊模組" aria-label="Permalink to &quot;6. 波若威 (3163) — 光通訊模組&quot;">​</a></h3><p><strong>核心產品：</strong> 高速光通訊模組、矽光子相關產品</p><p><strong>關鍵進展：</strong></p><ul><li>2026 年受惠於輝達 Rubin Ultra 世代登場</li><li>與光聖、眾達-KY 同屬 CPO 漲停族群</li></ul><p><strong>市場定位：</strong></p><ul><li>高盈餘高毛利（市場評分 65.52%）</li><li>受惠於 800G/1.6T 升級週期</li></ul><p><strong>資料來源：</strong></p><ol><li>Cnyes (2026-01-28)：矽光子族群漲停分析</li></ol><hr><h2 id="三、六家公司比較總表" tabindex="-1">三、六家公司比較總表 <a class="header-anchor" href="#三、六家公司比較總表" aria-label="Permalink to &quot;三、六家公司比較總表&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">公司</th><th style="text-align:left;">代號</th><th style="text-align:left;">核心技術</th><th style="text-align:left;">2026 關鍵產品</th><th style="text-align:left;">市場預期年增</th><th style="text-align:left;">主要風險</th></tr></thead><tbody><tr><td style="text-align:left;">全新光電</td><td style="text-align:left;">2455</td><td style="text-align:left;">InP/GaAs 磊晶</td><td style="text-align:left;">1.6T PD、CW Laser</td><td style="text-align:left;">19%–25.7%</td><td style="text-align:left;">InP 基板供應、毛利率下滑</td></tr><tr><td style="text-align:left;">IET-KY 新思</td><td style="text-align:left;">6530</td><td style="text-align:left;">VCSEL + QD 雷射</td><td style="text-align:left;">200G VCSEL、QD 雷射</td><td style="text-align:left;">29.84%</td><td style="text-align:left;">QD 量產時程不確定</td></tr><tr><td style="text-align:left;">上詮</td><td style="text-align:left;">3362</td><td style="text-align:left;">FAU 光纖陣列</td><td style="text-align:left;">1.6T/3.2T FAU</td><td style="text-align:left;">N/A（高增長確定）</td><td style="text-align:left;">台積電 COUPE 量產時程</td></tr><tr><td style="text-align:left;">眾達-KY</td><td style="text-align:left;">4977</td><td style="text-align:left;">CPO 光學模組</td><td style="text-align:left;">51.2T CPO 方案</td><td style="text-align:left;">EPS +~10%</td><td style="text-align:left;">博通客戶集中度高</td></tr><tr><td style="text-align:left;">光聖</td><td style="text-align:left;">6442</td><td style="text-align:left;">InP 雷射晶片</td><td style="text-align:left;">800G/1.6T 光模組</td><td style="text-align:left;">EPS &gt;40 元</td><td style="text-align:left;">股價已創新高</td></tr><tr><td style="text-align:left;">波若威</td><td style="text-align:left;">3163</td><td style="text-align:left;">光通訊模組</td><td style="text-align:left;">800G/1.6T 模組</td><td style="text-align:left;">N/A（高毛利）</td><td style="text-align:left;">客戶集中度</td></tr></tbody></table><hr><h2 id="四、產業展望與投資建議" tabindex="-1">四、產業展望與投資建議 <a class="header-anchor" href="#四、產業展望與投資建議" aria-label="Permalink to &quot;四、產業展望與投資建議&quot;">​</a></h2><p><strong>短期（2026 H2–2027）：</strong></p><ul><li>台積電 COUPE 量產 → 上詮、光聖直接受惠</li><li>全新 1.6T PD + CW Laser 放量 → 營收結構轉型加速</li><li>IET-KY 200G VCSEL 量產 → AI 資料中心 Scale-out 需求</li></ul><p><strong>中期（2027–2028）：</strong></p><ul><li>3.2T/6.4T 產品放量 → 上詮、全新領先</li><li>CPO 大規模商用 → 眾達-KY、光聖、波若威受益</li><li>QD 雷射低軌衛星應用 → IET-KY 第二成長曲線</li></ul><p><strong>風險提醒：</strong></p><ul><li>InP 基板供應持續吃緊（中國出口管制）</li><li>CSP 建置節奏不確定</li><li>股價已反映部分預期，注意估值風險</li></ul><hr><p><strong>研究日期：</strong> 2026-05-04 <strong>資料來源彙整：</strong> 鉅亨網、TechNews 科技新報、Pocket 學堂、Cnyes、TrendForce <strong>研究方法：</strong> web_search (Google/Bing) + tavily_extract 多源交叉驗證</p>',97)])])}const P=l(r,[["render",a]]);export{h as __pageData,P as default};
